// Build supplement analysis prompt
const user = $('Get User Profile').item.json;
const logs = $('Get Recent 7-Day Logs').all().map(i => i.json);
const lastRec = $('Get Last Supplement Rec').item.json;
const systemPromptRaw = $('Read System Prompt').item.json;
const fragmentRaw = $('Read Supplement Prompt').item.json;

const systemPrompt = typeof systemPromptRaw === 'string' ? systemPromptRaw : (systemPromptRaw.data || JSON.stringify(systemPromptRaw));
let fragment = typeof fragmentRaw === 'string' ? fragmentRaw : (fragmentRaw.data || JSON.stringify(fragmentRaw));

// Substitute fragment variables
fragment = fragment.replace(/{goal}/g, user.goal || 'maintenance');

// Build nutrition summary from 7-day logs
const avgProtein = logs.length > 0
  ? (logs.reduce((s, d) => s + (parseFloat(d.protein_g) || 0), 0) / logs.length).toFixed(1)
  : 0;
const avgCalories = logs.length > 0
  ? Math.round(logs.reduce((s, d) => s + (d.calories_consumed || 0), 0) / logs.length)
  : 0;
const avgSleep = logs.length > 0
  ? (logs.reduce((s, d) => s + (parseFloat(d.sleep_hours) || 0), 0) / logs.length).toFixed(1)
  : 0;
const avgEnergy = logs.length > 0
  ? (logs.reduce((s, d) => s + (d.energy_level || 0), 0) / logs.length).toFixed(1)
  : 0;

const foodDescriptions = logs
  .filter(d => d.food_description)
  .map((d, i) => `Day ${i+1}: ${d.food_description}`)
  .join('\n') || 'No food descriptions logged.';

const lastRecText = lastRec?.recommendations
  ? `Previous recommendations (${lastRec.recommended_at?.split('T')[0] || 'unknown date'}): ${JSON.stringify(lastRec.recommendations).substring(0, 300)}`
  : 'First supplement recommendation for this user.';

const userPrompt = `Provide personalized supplement advice for this user:\n\n` +
  `USER PROFILE:\n` +
  `Name: ${user.first_name} | Age: ${user.age} | Gender: ${user.gender}\n` +
  `Weight: ${user.weight_kg}kg | Goal: ${user.goal} | Activity: ${user.activity_level}\n` +
  `Daily calorie target: ${user.daily_calorie_target} kcal\n\n` +
  `7-DAY NUTRITION AVERAGES:\n` +
  `Avg calories: ${avgCalories} kcal | Avg protein: ${avgProtein}g\n` +
  `Avg sleep: ${avgSleep}h | Avg energy: ${avgEnergy}/10\n\n` +
  `RECENT FOOD LOG:\n${foodDescriptions}\n\n` +
  `PREVIOUS RECOMMENDATION:\n${lastRecText}\n\n` +
  fragment;

return [{ json: {
  systemPrompt,
  userPrompt,
  userId: user.id,
  telegramId: user.telegram_id,
  goal: user.goal
} }];

// Parse and structure the supplement response
const aiContent = $json.message?.content || $json.choices?.[0]?.message?.content || '';
const prevData = $('Build Supplement Prompt').item.json;

// Extract supplement list with basic parsing
const lines = aiContent.split('\n');
const recommendations = [];
const gaps = [];

lines.forEach(line => {
  const trimmed = line.trim();
  if (trimmed.match(/^[-•*]/) && (trimmed.includes('mg') || trimmed.includes('mcg') || trimmed.includes('g '))) {
    recommendations.push(trimmed.replace(/^[-•*]\s*/, ''));
  }
  if (trimmed.toLowerCase().includes('gap') || trimmed.toLowerCase().includes('deficien')) {
    gaps.push(trimmed);
  }
});

return [{ json: {
  fullResponse: aiContent,
  recommendations: recommendations.slice(0, 5),
  gaps: gaps.slice(0, 3),
  userId: prevData.userId,
  telegramId: prevData.telegramId,
  goal: prevData.goal
} }];

